  static final Map<String, dynamic> adeyaForAllMuslims ={
    "category": "أدعية للمسلمين",
    "azkar": [
      {
        "zekr": "اللهم إنا نسألك زيادة في الإيمان وبركة في العمر، وصحة في الجسد، وسعة في الرزق، وتوبة قبل الموت، وشهادة عند الموت، ومغفرة بعد الموت، وعفواً عند الحساب، وأماناً من العذاب، ونصيباً من الجنة، وارزقنا النظر إلى وجهك الكريم، اللهم ارحم موتانا وموتى المسلمين، واشفي مرضانا ومرضى المسلمين.\nاللهم اغفر للمسلمين والمسلمات، والمؤمنين والمؤمنات، الأحياء منهم والأموات.\nاللهم من اعتز بك فلن يذل، ومن اهتدى بك فلن يضل، ومن استكثر بك فلن يقل، ومن استقوى بك فلن يضعف، ومن استغنى بك فلن يفتقر، ومن استنصر بك فلن يخذل، ومن استعان بك فلن يغلب، ومن توكل عليك فلن يخيب، ومن جعلك ملاذه فلن يضيع، ومن اعتصم بك فقد هدي إلى صراط مستقيم.\nاللهم كن لنا ولياً ونصيراً، وكن لنا معيناً ومجيراً، إنك كنت بنا بصيراً.\nاللهم أحينا في الدنيا مؤمنين طائعين، وتوفنا مسلمين تائبين.\nاللهم ارحم تضرعنا بين يديك، وقوّمنا إذا اعوججنا، وادعنّا إذا استقمنا، وكن لنا ولا تكن علينا.\nاللهم نسألك يا غفور يا رحمن يا رحيم أن تفتح لأدعيتنا أبواب الإجابة، يا من إذا سأله المضطر أجاب، يا من يقول للشيء كن فيكون.\nاللهم لا تردنا خائبين، وآتنا أفضل ما يؤتى عبادك الصالحين، اللهم ولا تصرفنا عن بحر جودك خاسرين، ولا ضالين ولا مضلين، واغفر لنا إلى يوم الدين، برحمتك يا أرحم الرحمين.\nاللهم إنا نسألك من خير ما سألك به سيدنا محمد صلى الله عليه وسلم، ونستعيذ بك من شر ما استعاذ به سيدنا محمد صلى الله عليه وسلم.\nاللهم ارزقنا مغفرتك بلا عذاب، وجنتك بلا حساب، ورؤيتك بلا حجاب.\nاللهم يا عزيز يا جبار، اجعل قلوبنا تخشع من تقواك، واجعل عيوننا تدمع من خشياك، واجعلنا يا رب من أهل التقوى وأهل المغفرة.\nاللهم اغفر لجميع موتى المسلمين الذين شهدوا لك بالوحدانية ولنبيك بالرسالة وماتوا على ذلك، اللهم اغفر لهم وعافهم واعف عنهم وأكرم نزلهم ووسع مدخلهم، اللهم اجعل قبورهم روضة من رياض الجنة ولا تجعلها حفرة من حفر النار، اللهم ارحم وحشتهم في القبور وأمنهم يوم البعث والنشور، وجازهم بالإحسان إحساناً وبالسيئات غفراناً، وأنزل على قبورهم الضياء والنور والفسحة والسرور، وانقلهم من ضيق اللحود إلى جناتك جنات الخلود.",
        "count": 1,
        "target": "أدعية عامة للمسلمين"
      }
    ]
  };
  static final Map<String, dynamic> fadlAlSowar ={
    "category": "فضل السور",
    "azkar": [
      {
        "benfits": [
          {
            "hadith": ''' أَلاَ أُعَلِّمُكَ أَعْظَمَ سُورَةٍ فِي القُرْآنِ قَبْلَ أَنْ أَخْرُجَ مِنَ المَسْجِدِ". فَذَهَبَ النَّبِيُّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ لِيَخْرُجَ مِنَ المَسْجِدِ فَذَكَّرْتُهُ، فَقَالَ: "(الحَمْدُ لِلَّهِ رَبِّ العَالَمِينَ). هِيَ السَّبْعُ المَثَانِي، وَالقُرْآنُ العَظِيمُ الَّذِي أُوتِيتُهُ». رَوَاه البُخَارِي (6/ 4474)، وأَحمَد (24/ 15730).''',
            "reference": "عَنْ أَبِي سَعِيدِ بْنِ المُعَلَّى رَضِيَ اللَّهُ عَنْهُ، قَالَ: قَالَ لِيَ النَّبِيُّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ"
          },
