  static final Map<String, dynamic> fadlAlThekr ={
    "category": "فضل الذكر",
    "azkar": [
      {
        "zekr": '''ورد في فضل الذكر والدعاء والحث عليها آيات كثيرة، وأحاديث صحيحة عن رسول الله صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ، نذكر ما تيسر منها.\nقال تعالى : "وَلَذِكْرُ اللَّهِ أَكْبَرُ".\nوقال تعالى : "وَسَبِّحُوهُ بُكْرَةً وَأَصِيلًا".\nوقال تعالى : "فَاذْكُرُونِي أَذْكُرْكُمْ وَاشْكُرُوا لِي وَلا تَكْفُرُونِ".\nوقال تعالى : "يَا أَيُّهَا الَّذِينَ آمَنُوا اذْكُرُوا اللَّهَ ذِكْراً كَثِيراً".\nوقال تعالى : "وَالذَّاكِرِينَ اللَّهَ كَثِيراً وَالذَّاكِرَاتِ أَعَدَّ اللَّهُ لَهُمْ مَغْفِرَةً وَأَجْراً عَظِيماً".\nوقال تعالى : "وَاذْكُر رَّبَّكَ كَثِيرًا وَسَبِّحْ بِالْعَشِيِّ وَالْإِبْكَارِ".\nوقال تعالى : "الَّذِينَ يَذْكُرُونَ اللَّهَ قِيَامًا وَقُعُودًا وَعَلَىٰ جُنُوبِهِمْ".\nوقال تعالى : "فَإِذَا قَضَيْتُم مَّنَاسِكَكُمْ فَاذْكُرُوا اللَّهَ كَذِكْرِكُمْ آبَاءَكُمْ أَوْ أَشَدَّ ذِكْرًا".\nوقال تعالى : "يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تُلْهِكُمْ أَمْوَالُكُمْ وَلَا أَوْلَادُكُمْ عَن ذِكْرِ اللَّهِ".\nوقال تعالى : "وَاذْكُرْ رَبَّكَ فِي نَفْسِكَ تَضَرُّعاً وَخِيفَةً وَدُونَ الْجَهْرِ مِنْ الْقَوْلِ بِالْغُدُوِّ وَالآصَالِ وَلا تَكُنْ مِنْ الْغَافِلِينَ".\nو قال رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ: "مثل الذي يذكر ربه و الذي لا يذكر ربه مثل الحي و الميت".\nو قال رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ: "ألا أنبئكم بخير أعمالكم و أزكاها عند مليككم و أرفعها في درجاتكم و خير لكم من أنفاق الذهب و الورق و خير لكم من أن تلقوا عدوكم فتضربوا أعناقهم و يضربوا أعناقكم؟ " قالو بلى . قال : (ذكر الله تعالى).\nو قال رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ: "يقول الله تعالى : أنا عند ظن عبدي بي , و أنا معه إذا ذكرني , فان ذكرني في نفسه ذكرته في نفسي و ان ذكرني في ملأ ذكرته في ملأ خير منهم , و ان تقرب إلي شبرا تقربت اليه ذراعا و ان تقرب إلى ذراعا تقربت اليه باعا و ان اتاني يمشي أتيته هرولة.\nو قال رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ: "من قعد مقعدا لم يذكر الله فيه كانت عليه من الله تره , و من أضطجع مضجعا لم يذكر فيه الله كانت عليه ترة".\nو قال رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ: "ما جلس قوم مجلسا لم يذكروا الله فيه , و لم يصلوا على نبيهم الا كان عليهم ترة فان شاء عذبهم و ان شاء غفر لهم".\nو قال رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ: "ما من قوم يقومون من مجلس لا يذكرون الله فيه الا قاموا عن مثل جيفة حمار و كان لهم حسره".''',
        "title": "آيات وأحاديث في فضل الذكر والدعاء والحث عليها",
      },
      {
        "zekr": '''أنه يطرد الشيطان ويقمعه ويكسره.\nأنه يرضي الرحمن عز وجل.\nأنه يزيل الهم والغم عن القلب.\nأنه يجلب للقلب الفرح والسرور والبسط.\nأنه يجلب الرزق.\nأنه يكسو الذاكر المهابة والحلاوة والنضرة.\nأنه يورثه المحبة التي هي روح الإسلام وقطب رحى الدين ومدار السعادة والنجاة وقد جعل الله لكل شئ سببا وجعل سبب المحبة دوام الذكر فمن اراد ان ينال محبة الله عز وجل فليلهج بذكره فانه الدرس والمذاكرة كما انه باب العلم فالذكر باب المحبة وشارعها الأعظم وصراطها الأقوام.\nأنه يورثه المراقبة حتى يدخله في باب الإحسان فيعبد الله كأنه يراه ولا سبيل للغافل عن الذكر إلى مقام الإحسان كما لا سبيل للقاعد إلى الوصول إلى البيت.\nأنه يورثه الإنابة وهي الرجوع إلى الله عز وجل فمتى اكثر الرجوع إليه بذكره أورثه ذلك رجوعه بقلبه إليه في كل أحواله فيبقى الله عز وجل مفزعه وملجأه وملاذه ومعاذه وقبلة قلبه ومهربه عند النوازل والبلايا.\nأنه يورث الهيبة لربه عز وجل وإجلاله لشدة استيلائه على قلبه وحضوره مع الله تعالى بخلاف الغافل فان حجاب الهيبة رقيق في قلبه.\nأنه يورثه ذكر الله تعالى له كما قال تعالى: ( فاذكروني أذكركم) ولو لم يكن في الذكر إلا هذه وحدها لكفى بها فضلا وشرفا وقال فيما يروي عن ربه تبارك وتعالى . ( من ذكرني في نفسه ذكرته في نفسي ومن ذكرني في ملا ذكرته في ملا خير منهم) . رواه البخاري ومسلم.\nأنه يحط الخطايا ويذهبها فانه من اعظم الحسنات والحسنات يذهبن السيئات.\nأنه يزيل الوحشة بين العبد وبين ربه تبارك وتعالى فان الغافل بينه وبين الله عز وجل وحشه لا تزول إلا بالذكر.\nأن العبد إذا تعرف إلى الله تعالى بذكره في الرخاء عرفه في الشدة وقد جاء اثر معناه أن العبد المطيع الذاكر لله تعالى إذا أصابته شدة أو سأل الله تعالى حاجة قالت الملائكة يا رب صوت معروف من عبد معروف والغافل المعرض عن الله عز وجل إذا دعاه وسأله قالت الملائكة يارب صوت منكر من عبد منكر – وحديث ابن عباس تعرف إلى الله في الرخاء يعرفك في الشدة – رواه الإمام أحمد\nأنه ينجي من عذاب الله تعالى كما قال معاذ رضي الله عنه ويروى مرفوعا (ما عمل ادمي عملا أنجي من عذاب الله عز وجل من ذكر الله تعالى ). رواه أحمد ومالك وابن ماجة والترمذي.\nأنه سبب تنزيل السكينة وغشيان الرحمة وحفوف الملائكة بالذاكر كما اخبر به النبي صلى الله عليه وسلم . – الحديث : ( لا يقعد قوم يذكرون الله إلا حفتهم الملائكة وغشيتهم الرحمة ونزلت عليهم السكينة وذكرهم الله فيمن عنده ) رواه مسلم.\nأنه سبب اشتغال اللسان عن الغيبة والنميمة والكذب والفحش والباطل فان العبد لا بد له من ان يتكلم فإن لم يتكلم بذكر الله تعالى وذكر أوامره تكلم بهذه المحرمات أو بعضها ولا سبيل إلى السلامة منها البتة إلا بذكر الله تعالى والمشاهدة والتجربة شاهدان بذلك فمن عود لسانه ذكر الله صان لسانه عن الباطل واللغو ومن يبس لسانه عن ذكر الله تعالى ترطب بكل باطل ولغو وفحش ولا حول ولا قوة إلا بالله.\nأنه يؤمن العبد من الحسرة يوم القيامة فان كل مجلس لا يذكر العبد فيه ربه تعالى كان عليه حسرة وترة يوم القيامة.\nأنه أيسر العبادات وهو من اجلها وأفضلها فان حركة اللسان اخف حركات الجوارح وأيسرها ولو تحرك عضو من الإنسان في اليوم والليلة بقدر حركة لسانه لشق عليه غاية المشقة بل لا يمكنه ذلك . وفي الحديث : ( كلمتان خفيفتان على اللسان ثقيلتان في الميزان حبيبتان إلى الرحمن : سبحان الله وبحمده سبحان الله العظيم ).\nأنه غراس الجنة. في الترمذي من حديث أبى الزبير عن جابر عن النبي قال : ( من قال سبحان الله وبحمده غرست له نخله في الجنة ) قال الترمذي حديث حسن صحيح ، وصححه الألباني في صحيح الجامع - 6429.\nأن العطاء والفضل الذي رتب عليه لم يرتب على غيره من الأعمال ففي الصحيحين عن أبى هريرة رضي الله عنه أن رسول الله قال : ( من قال لا اله إلا الله وحده لا شريك له له الملك وله الحمد وهو على كل شئ قدير في يوم مائة مرة كانت له عدل عشر رقاب وكتبت له مائة حسنة ومحيت عنه مائة سيئة وكانت له حرزا من الشيطان يومه ذلك حتى يمسي و لم يات احد بافضل مما جاء به الا رجل عمل اكثر منه ومن قال سبحان الله وبحمده في يوم مائة مرة حطت خطاياه وان كانت مثل زبد البحر ) وفي صحيح مسلم عن أبي هريرة قال قال رسول الله لان أقول سبحان الله والحمد لله ولا اله الا الله والله اكبر احب الي مما طلعت عليه الشمس ).\nأن دوام ذكر الرب تبارك وتعالى يوجب الأمان من نسيانه الذي هو سبب شقاء العبد في معاشه ومعاده فان نسان الرب سبحانه وتعالى يوجب نسيان نفسه ومصالحها قال تعالى : ( ولا تكونوا كالذين نسوا الله فانساهم انفسهم اولئك هم الفاسقون ) وإذا نسي العبد نفسه اعرض عن مصالحها ونسيها واشتغل عنها فهلكت وفسدت ولا بد. فمن نسي الله تعالى أنساه نفسه في الدنيا ونسيه في العذاب يوم القيامة قال تعالى ( ومن اعرض عن ذكري فان له معيشة ضنكا ونحشره يوم القيامة أعمى قال رب لم حشرتني اعمى وقد كنت بصيرا قال كذلك اتتك اياتنا فنسيتها وكذلك اليوم تنسى ) أي تنسى في العذاب كما نسيت اياتي فلم تذكرها ولم تعمل بها.\nأن الذكر نور للذاكر في الدنيا ونور له في قبره ونور له في معاده يسعى بين يديه على الصراط فما استنارت القلوب والقبور بمثل ذكر الله تعالى قال الله تعالى : ( أومن كان ميتا فأحييناه وجعلنا له نورا يمشي به في الناس كمن مثله في الظلمات ليس بخارج منها) فالأول هو المؤمن استنار بالإيمان بالله ومحبته ومعرفته وذكره والآخر هو الغافل عن الله تعالى المعرض عن ذكره ومحبته والشان كل الشان والفلاح كل الفلاح في النور والشقاء كل الشقاء في فواته.\nأن الذكر يجمع المتفرق و يفرق المجتمع ويقرب البعيد ويبعد القريب\nأن في القلب قسوة لا يذيبها إلا ذكر الله تعالى فينبغي للعبد أن يداوي قسوة قلبه بذكر الله تعالى وذكر حماد بن زيد عن المعلى ابن زياد ان رجلا قال للحسن يا أبا سعيد أشكو إليك قسوة قلب قال أذبه بالذكر وهذا لان القلب كلما اشتدت به الغفلة اشتدت به القسوة فاذا ذكر الله تعالى ذابت تلك القسوة كما يذوب الرصاص في النار فلما اذيبت قسوة القلوب بمثل ذكر الله عز وجل.\nأن الذكر يوجب صلاة الله عز وجل وملائكته على الذاكر ومن صلى الله تعالى عليه وملائكته فقد افلح كل الفلاح وفاز كل الفوز قال سبحانه وتعالى : ( يا أيها الذين امنوا اذكروا الله ذكرا كثيرا و سبحوه بكرة وأصيلا هو الذي يصلى عليكم وملائكته ليخرجكم من الظلمات إلى النور وكان بالمؤمنين رحيما ).\nأن مجالس الذكر مجالس الملائكة فليس من مجالس الدنيا لهم مجلس الا مجلس يذكر الله تعالى فيه كما أخرجا في الصحيحين من حديث الاعمش عن ابي صالح عن أبى هريرة قال رسول الله إن لله ملائكة فضلا عن كتاب الناس يطوفون في الطرق يلتمسون اهل الذكر فاذا وجدوا قوما يذكرون الله تعالى تنادوا هلموا الى حاجتكم قال فيحفونهم باجنحتهم الى السماء الدنيا فيسالهم ربهم تعالى وهو اعلم بهم ما يقول عبادي قال يقولون يسبحونك ويكبرونك ويحمدونك قال فيقول هل رأوني قال فيقولون لا والله ما رأوك قال فيقول كيف لو رأوني قال فيقولون لو رأوك كانوا اشد لك عبادة واشد لك تحميدا وتمجيدا واكثر لك تسبيحا قال فيقول ما يسالوني قال يسالونك الجنة قال يقول وهل راوها قال يقولن لا والله يارب ماراوها قال فيقول فكيف لو انهم راوها قال يقولون لو انهم راوها كانوا اشد عليها حرصا واشد لها طلبا واعظم فيها رغبة فيقول فمم يتعوذون قال يقولون من النار قال يقول وهل راوها قال يقولون لا والله يارب ماراوها قال يقول فكيف لو راوها قال يقولون لو راوها كانوا اشد منها فرارا واشد لها مخافة قال يقول فأشهدكم اني قد غفرت لهم فيقول ملك من الملائكة فيهم فلان ليس منهم و انما جاء لحاجة قال هم الجلساء لا يشقى بهم جليسهم ) فهذا من بركتهم على نفوسهم وعلى جليسهم فلهم نصيب من قوله وجعلني مباركا اينما كنت فهكذا المؤمن مبارك اين حل والفاجر مشئوم اين حل فمجالس الذكر مجالس الملائكة ومجالس الغفلة مجالس الشياطين وكل مضاف الى شكله واشباهه امرئ يصير الى ما يناسبه.\nأن الله عز وجل يباهي بالذاكرين ملائكته كما روى مسلم في صحيحه عن أبى سعيد الخدري قال خرج معاوية على حلقة في المسجد فقال ما أجلسكم قالوا جلسنا نذكر الله تعالى قال الله ما أجلسكم إلا ذاك قالوا والله ما أجلسنا إلا ذاك قال أما أنى لم استحلفكم تهمة لكم وما كان احد بمنزلتي من رسول الله اقل عنه حديثا مني وان رسول الله خرج على حلقة من أصحابه فقال : ( ما أجلسكم قالوا جلسنا نذكر الله تعالى ونحمده على ما هدانا للإسلام ومن علينا بك قال الله ما أجلسكم ألا ذاك قالوا والله ما أجلسنا إلا ذاك قال أما أنى لم استحلفكم تهمة لكم ولكنه اتاني جبريل فاخبرني إن الله تبارك وتعالى يباهي بكم الملائكة ) فهذه المباهاة من الرب تبارك وتعالى دليل على شرف الذكر عنده ومحبته له وان له مزية على غيره من الأعمال.\nأن جميع الأعمال إنما شرعت إقامة لذكر الله تعالى والمقصود بها تحصيل ذكر الله تعالى قال سبحانه وتعالى : ( أقم الصلاة لذكري ).\nأن ذكر الله عز وجل يسهل الصعب وييسر العسير ويخفف المشاق فما ذكر الله عز وجل على صعب إلا هان ولا على عسير إلا تيسر ولا مشقة إلا خفت ولا شدة الا زالت ولا كربه الا انفرجت فذكر الله تعالى هو الفرج بعد الشدة واليسر بعد العسر والفرج بعد الغم والهم يوضحه.\nأن كثرة ذكر الله عز وجل أمان من النفاق فان المنافقين قليلو الذكر لله عز وجل قال الله عز وجل في المنافقين ولا يذكرون الله الا قليلا وقال كعب من اكثر ذكر الله عز وجل برئ من النفاق ولهذا والله اعلم ختم الله تعالى سورة المنافقين بقوله تعالى : ( يا أيها الذين امنوا لا تلهكم أموالكم ولا أولادكم عن ذكر الله ومن يفعل ذلك فاولئك هم الخاسرون ) فان في ذلك تحذيرا من فتنة المنافقين الذين غفلوا عن ذكر الله عز وجل فوقعوا في النفاق.''',
        "title": "فضائل الذكر للإمام ابن القيم الجوزية",
      },
    ]
  };
  static final List<Map<String, String>> asmaaAllahAlHusna = [
    {"name": "الله", "transliteration": "Allah", "meaning": "وهو الإسم الأعظم الذي تفرد به الحق سبحانه وخص به نفسه وجعله أول أسمائه، وأضافها كلها إليه فهو علم على ذاته سبحانه."},
    {"name": "الرحمن", "transliteration": "Ar-Rahman", "meaning": "كثير الرحمة وهو اسم مقصور على الله عز وجل ولا يجوز أن يقال رحمن لغير الله، وذلك لأن رحمته وسعت كل شيء وهو أرحم الراحمين."},
    {"name": "الرحيم", "transliteration": "Ar-Raheem", "meaning": "هو المنعم أبدا، المتفضل دوما، فرحمته لا تنتهي."},
    {"name": "الملك", "transliteration": "Al-Malik", "meaning": "هو الله، ملك الملوك، له الملك، وهو مالك يوم الدين، ومليك الخلق فهو المالك المطلق."},
    {"name": "القدوس", "transliteration": "Al-Quddus", "meaning": "هو الطاهر المنزه عن العيوب والنقائص وعن كل ما تحيط به العقول."},
    {"name": "السلام", "transliteration": "As-Salaam", "meaning": "هو ناشر السلام بين الأنام وهو الذي سلمت ذاته من النقص والعيب والفناء."},
    {"name": "المؤمن", "transliteration": "Al-Mu’min", "meaning": "هو الذي سلم أوليائه من عذابه، والذي يصدق عباده ما وعدهم."},
    {"name": "المهيمن", "transliteration": "Al-Muhaymin", "meaning": "هو الرقيب الحافظ لكل شيء، القائم على خلقه بأعمالهم، وأرزاقهم وآجالهم، المسؤول عنهم بالرعاية والوقاية والصيانة."},
    {"name": "العزيز", "transliteration": "Al-Aziz", "meaning": "هو المنفرد بالعزة، الظاهر الذي لا يقهر، القوي الممتنع فلا يغلبه شيء وهو غالب كل شيء."},
    {"name": "الجبار", "transliteration": "Al-Jabbar", "meaning": "هو الذي تنفذ مشيئته، ولا يخرج أحد عن تقديره، وهو القاهر لخلقه على ما أراد."},
    {"name": "المتكبر", "transliteration": "Al-Mutakabbir", "meaning": "هو المتعالى عن صفات الخلق المنفرد بالعظمة والكبرياء."},
    {"name": "الخالق", "transliteration": "Al-Khaliq", "meaning": "هو الفاطر المبدع لكل شيء، والمقدر له والموجد للأشياء من العدم، فهو خالق كل صانع وصنعته."},
    {"name": "البارئ", "transliteration": "Al-Bari’", "meaning": "هو الذي خلق الخلق بقدرته لا عن مثال سابق، القادر على إبراز ما قدره إلى الوجود."},
    {"name": "المصور", "transliteration": "Al-Musawwir", "meaning": "هو الذي صور جميع الموجودات، ورتبها فأعطى كل شيء منها صورة خاصة، وهيئة منفردة، يتميز بها على اختلافها وكثرتها."},
    {"name": "الغفار", "transliteration": "Al-Ghaffar", "meaning": "هو وحده الذي يغفر الذنوب ويستر العيوب في الدنيا والآخرة."},
    {"name": "القهار", "transliteration": "Al-Qahhar", "meaning": "هو الغالب الذي قهر خلقه بسلطانه وقدرته، وصرفهم على ما أراد طوعا وكرها، وخضع لجلاله كل شيء."},
    {"name": "الوهاب", "transliteration": "Al-Wahhab", "meaning": "هو المنعم على العباد، الذي يهب بغير عوض ويعطي الحاجة بغير سؤال، كثير النعم، دائم العطاء."},
    {"name": "الرزاق", "transliteration": "Ar-Razzaq", "meaning": "هو الذي خلق الأرزاق وأعطى كل الخلائق أرزاقها، ويمد كل كائن لما يحتاجه، ويحفظ عليه حياته ويصلحه."},
    {"name": "الفتاح", "transliteration": "Al-Fattah", "meaning": "هو الذي يفتح مغلق الأمور، ويسهل العسير، وبيده مفاتيح السماوات والأرض."},
    {"name": "العليم", "transliteration": "Al-‘Aleem", "meaning": "هو الذي يعلم تفاصيل الأمور، ودقائق الأشياء وخفايا الضمائر، والنفوس، لا يغرب عن ملكه مثقال ذرة، فعلمه يحيط بجميع الأشياء."},
    {"name": "القابض", "transliteration": "Al-Qabid", "meaning": "هو الذي يقبض الرزق عمن يشاء من الخلق بعدله، والذي يوسع الرزق لمن يشاء من عباده بجوده ورحمته فهو سبحانه القابض الباسط."},
    {"name": "الباسط", "transliteration": "Al-Basit", "meaning": "هو الذي يقبض الرزق عمن يشاء من الخلق بعدله، والذي يوسع الرزق لمن يشاء من عباده بجوده ورحمته فهو سبحانه القابض الباسط."},
    {"name": "الخافض", "transliteration": "Al-Khafid", "meaning": "هو الذي يخفض الأذلال لكل من طغى وتجبر وخرج على شريعته وتمرد، وهو الذي يرفع عباده المؤمنين بالطاعات وهو رافع السماوات."},
    {"name": "الرافع", "transliteration": "Ar-Rafi‘", "meaning": "هو الذي يخفض الأذلال لكل من طغى وتجبر وخرج على شريعته وتمرد، وهو الذي يرفع عباده المؤمنين بالطاعات وهو رافع السماوات."},
    {"name": "المعز", "transliteration": "Al-Mu‘izz", "meaning": "هو الذي يهب القوة والغلبة والشدة لمن شاء فيعزه، وينزعها عمن يشاء فيذله."},
    {"name": "المذل", "transliteration": "Al-Mudhill", "meaning": "هو الذي يهب القوة والغلبة والشدة لمن شاء فيعزه، وينزعها عمن يشاء فيذله."},
    {"name": "السميع", "transliteration": "As-Sami‘", "meaning": "هو الذي لا يخفى عليه شيء في الأرض ولا في السماء وهو السميع البصير."},
    {"name": "البصير", "transliteration": "Al-Basir", "meaning": "هو الذي يرى الأشياء كلها ظاهرها وباطنها وهو المحيط بكل شيئ علماً."},
    {"name": "الحكم", "transliteration": "Al-Hakam", "meaning": "هو الذي يفصل بين مخلوقاته بما شاء ويفصل بين الحق والباطل لا راد لقضائه ولا معقب لحكمه."},
    {"name": "العدل", "transliteration": "Al-‘Adl", "meaning": "هو الذي حرم الظلم على نفسه، وجعله على عباده محرما، فهو المنزه عن الظلم والجور في أحكامه وأفعاله الذي يعطي كل ذي حق حقه."},
    {"name": "اللطيف", "transliteration": "Al-Latif", "meaning": "هو البر الرفيق بعباده، يرزق وييسر ويحسن إليهم، ويرفق بهم ويتفضل عليهم."},
    {"name": "الخبير", "transliteration": "Al-Khabir", "meaning": "هو العليم بدقائق الأمور، لا تخفى عليه خافية، ولا يغيب عن علمه شيء فهو العالم بما كان ويكون."},
    {"name": "الحليم", "transliteration": "Al-Haleem", "meaning": "هو الصبور الذي يمهل ولا يهمل، ويستر الذنوب، ويؤخر العقوبة، فيرزق العاصي كما يرزق المطيع."},
    {"name": "العظيم", "transliteration": "Al-‘Azim", "meaning": "هو الذي ليس لعظمته بداية ولا لجلاله نهاية، وليس كمثله شيء."},
    {"name": "الغفور", "transliteration": "Al-Ghafoor", "meaning": "هو الساتر لذنوب عباده المتجاوز عن خطاياهم وذنوبهم."},
    {"name": "الشكور", "transliteration": "Ash-Shakur", "meaning": "هو الذي يزكو عنده القليل من أعمال العباد، فيضاعف لهم الجزاء، وشكره لعباده مغفرته لهم."},
    {"name": "العلي", "transliteration": "Al-‘Aliyy", "meaning": "هو الرفيع القدر فلا يحيط به وصف الواصفين المتعالي عن الأنداد والأضداد، فكل معاني العلو ثابتة له ذاتا وقهرا وشأنا."},
    {"name": "الكبير", "transliteration": "Al-Kabir", "meaning": "هو العظيم الجليل ذو الكبرياء في صفاته وأفعاله فلا يحتاج إلى شيء ولا يعجزه شيء (ليس كمثله شيء)."},
    {"name": "الحفيظ", "transliteration": "Al-Hafeez", "meaning": "هو الذي لا يغرب عن حفظه شيء ولو كمثقال الذر فحفظه لا يتبدل ولا يزول ولا يعتريه التبديل."},
    {"name": "المقيت", "transliteration": "Al-Muqit", "meaning": "هو المتكفل بإيصال أقوات الخلق إليهم وهو الحفيظ والمقتدر والقدير والمقدر والممدد."},
    {"name": "الحسيب", "transliteration": "Al-Haseeb", "meaning": "هو الكافي الذي منه كفاية العباد وهو الذي عليه الإعتماد يكفي العباد بفضله."},
    {"name": "الجليل", "transliteration": "Al-Jaleel", "meaning": "هو العظيم المطلق المتصف بجميع صفات الكمال والمنعوت بكمالها المنزه عن كل نقص."},
    {"name": "الكريم", "transliteration": "Al-Kareem", "meaning": "هو الكثير الخير الجواد المعطي الذي لا ينفذ عطاؤه وهو الكريم المطلق الجامع لأنواع الخير والشرف والفضائل المحمود بفعاله."},
    {"name": "الرقيب", "transliteration": "Ar-Raqeeb", "meaning": "هو الرقيب الذي يراقب أحوال العباد ويعلم أقوالهم ويحصي أعمالهم وهو الحافظ الذي لا يغيب عنه شيء."},
    {"name": "المجيب", "transliteration": "Al-Mujeeb", "meaning": "هو الذي يجيب دعاء من دعاه، وسؤال من سأله، ويقابله بالعطاء والقبول، ولا يسأل أحد سواه."},
    {"name": "الواسع", "transliteration": "Al-Waasi‘", "meaning": "هو الذي وسع رزقه جميع خلقه، وسعت رحمته كل شيء المحيط بكل شيء."},
    {"name": "الحكيم", "transliteration": "Al-Hakeem", "meaning": "هو المحق في تدبيره اللطيف في تقديره الخبير بحقائق الأمور العليم بحكمه المقدور فجميع خلقه وقضاه خير وحكمة وعدل."},
    {"name": "الودود", "transliteration": "Al-Wadud", "meaning": "هو المحب لعباده، والمحبوب في قلوب أوليائه."},
    {"name": "المجيد", "transliteration": "Al-Majeed", "meaning": "هو البالغ النهاية في المجد، الكثير الإحسان الجزيل العطاء العظيم البر."},
    {"name": "الباعث", "transliteration": "Al-Ba‘ith", "meaning": "هو باعث الخلق يوم القيامة، وباعث رسله إلى العباد، وباعث المعونة إلى العبد."},
    {"name": "الشهيد", "transliteration": "Ash-Shaheed", "meaning": "هو الحاضر الذي لا يغيب عنه شيء، فهو المطلع على كل شيء مشاهد له عليم بتفاصيله."},
    {"name": "الحق", "transliteration": "Al-Haqq", "meaning": "هو الذي يحق الحق بكلماته ويؤيد أولياءه فهو المستحق للعبادة."},
    {"name": "الوكيل", "transliteration": "Al-Wakeel", "meaning": "هو الكفيل بالخلق القائم بأمورهم فمن توكل عليه تولاه وكفاه، ومن استغنى به أغناه وأرضاه."},
    {"name": "القوي", "transliteration": "Al-Qawiyy", "meaning": "هو صاحب القدرة التامة البالغة الكمال غالب لا يغلب فقوته فوق كل قوة."},
    {"name": "المتين", "transliteration": "Al-Mateen", "meaning": "هو الشديد الذي لا يحتاج في إمضاء حكمه إلى جند أو مدد ولا إلى معين."},
    {"name": "الولي", "transliteration": "Al-Waliyy", "meaning": "هو المحب الناصر لمن أطاعه، ينصر أولياءه، ويقهر أعداءه، والمتولي الأمور الخلائق ويحفظهم."},
    {"name": "الحميد", "transliteration": "Al-Hameed", "meaning": "هو المستحق للحمد والثناء، الذي لا يحمد على مكروه سواه."},
    {"name": "المحصي", "transliteration": "Al-Muhsi", "meaning": "هو الذي أحصى كل شيء بعلمه، فلا يفوته منها دقيق ولا جليل."},
    {"name": "المبدئ", "transliteration": "Al-Mubdi’", "meaning": "هو الذي أنشأ الأشياء، واخترعها ابتداء من غير سابق مثال."},
    {"name": "المعيد", "transliteration": "Al-Mu‘id", "meaning": "هو الذي يعيد الخلق بعد الحياة إلى الممات في الدنيا، وبعد الممات إلى الحياة يوم القيامة."},
    {"name": "المحيي", "transliteration": "Al-Muhyi", "meaning": "هو خالق الحياة ومعطيها لمن شاء، يحيي الخلق من العدم ثم يحييهم بعد الموت."},
    {"name": "المميت", "transliteration": "Al-Mumeet", "meaning": "هو مقدر الموت على كل من أماته ولا مميت سواه، قهر عباده بالموت متى شاء وكيف شاء."},
    {"name": "الحي", "transliteration": "Al-Hayy", "meaning": "هو المتصف بالحياة الأبدية التي لا بداية لها ولا نهاية فهو الباقي أزلا وأبدا وهو الحي الذي لا يموت."},
    {"name": "القيوم", "transliteration": "Al-Qayyum", "meaning": "هو القائم بنفسه، الغني عن غيره، وهو القائم بتدبير أمر خلقه في إنشائهم ورزقهم."},
    {"name": "الواجد", "transliteration": "Al-Wajid", "meaning": "هو الذي لا يعوزه شيء ولا يعجزه شيء يجد كل ما يطلبه، ويدرك كل ما يريده."},
    {"name": "الماجد", "transliteration": "Al-Majid", "meaning": "هو الذي له الكمال المتناهي والعز الباهي، له العز في الأوصاف والأفعال الذي يعامل العباد بالجود والرحمة."},
    {"name": "الواحد", "transliteration": "Al-Wahid", "meaning": "هو الفرد المتفرد في ذاته وصفائه وأفعاله، واحد في ملكه لا ينازعه أحد، لا شريك له سبحانه."},
    {"name": "الصمد", "transliteration": "As-Samad", "meaning": "هو المطاع الذي لا يقضى دونه أمر، الذي يقصد إليه في الحوائج فهو مقصد عباده في مهمات دينهم ودنياهم."},
    {"name": "القادر", "transliteration": "Al-Qadir", "meaning": "هو الذي يقدر على إيجاد المعدوم وإعدام الموجود على قدر ما تقتضي الحكمة، لا زائدا عليه ولا ناقصا عنه."},
    {"name": "المقتدر", "transliteration": "Al-Muqtadir", "meaning": "هو الذي يقدر على إصلاح الخلائق على وجه لا يقدر عليه غيره."},
    {"name": "المقدم", "transliteration": "Al-Muqaddim", "meaning": "هو الذي يقدم الأشياء ويضعها في مواضعها، فمن استحق التقديم قدمه."},
    {"name": "المؤخر", "transliteration": "Al-Mu’akhkhir", "meaning": "هو الذي يؤخر الأشياء فيضعها في مواضعها المؤخر لمن شاء من الفجار والكفار وكل من يستحق التأخير."},
    {"name": "الأول", "transliteration": "Al-Awwal", "meaning": "هو الذي لم يسبقه في الوجود شيء فهو أول قبل الوجود."},
    {"name": "الآخر", "transliteration": "Al-Aakhir", "meaning": "هو الباقي بعد فناء خلقه، البقاء الأبدي يفنى الكل وله البقاء وحده، فليس بعده شيء."},
    {"name": "الظاهر", "transliteration": "Az-Zaahir", "meaning": "هو الذي ظهر فوق كل شيء وعلا عليه، الظاهر وجوده لكثرة دلائله."},
    {"name": "الباطن", "transliteration": "Al-Baatin", "meaning": "هو العالم ببواطن الأمور وخفاياها، وهو أقرب إلينا من حبل الوريد."},
    {"name": "الوالي", "transliteration": "Al-Waali", "meaning": "هو المالك للأشياء المتصرف فيها بمشيئته وحكمته، ينفذ فيها أمره، ويجري عليها حكمه."},
    {"name": "المتعالي", "transliteration": "Al-Muta‘ali", "meaning": "هو الذي جل عن إفك المفترين، وتنزه عن وساوس المتحيرين."},
    {"name": "البر", "transliteration": "Al-Barr", "meaning": "هو العطوف على عباده ببره ولطفه، ومن على السائلين بحسن عطائه، وهو الصدق فيما وعد."},
    {"name": "التواب", "transliteration": "At-Tawwab", "meaning": "هو الذي يوفق عباده للتوبة حتى يتوب عليهم ويقبل توبتهم فيقابل الدعاء بالعطاء، والتوبة بغفران الذنوب."},
    {"name": "المنتقم", "transliteration": "Al-Muntaqim", "meaning": "هو الذي يقسم ظهور الطغاة، ويشدد العقوبة على العصاة، وذلك بعد الإعذار والإنذار."},
    {"name": "العفو", "transliteration": "Al-‘Afuww", "meaning": "هو الذي يترك المؤاخدة على الذنوب ولا يذكرك بالعيوب فهو يمحو السيئات ويتجاوز عن المعاصي."},
    {"name": "الرؤوف", "transliteration": "Ar-Ra’oof", "meaning": "هو المتعطف على المذنبين بالتوبة، الذي جاد بلطفه ومن بتعطفه، يستر العيوب ثم يعفو عنها."},
    {"name": "مالك الملك", "transliteration": "Malik Al-Mulk", "meaning": "هو المتصرف في ملكه كيف يشاء لا راد لحكمه، ولا معقب لأمره."},
    {"name": "ذو الجلال والإكرام", "transliteration": "Dhul-Jalali wal-Ikram", "meaning": "هو المنفرد بصفات الجلال والكمال والعظمة، المختص بالإكرام والكرامة وهو أهل لأن يجل."},
    {"name": "المقسط", "transliteration": "Al-Muqsit", "meaning": "هو العادل في حكمه، الذي ينتصف للمظلوم من الظالم، ثم يكمل عدله فيرضي الظالم بعد إرضاء المظلوم."},
    {"name": "الجامع", "transliteration": "Al-Jami‘", "meaning": "هو الذي جمع الكمالات كلها، ذاتا ووصفا وفعلا، الذي يجمع بين الخلائق المتماثلة والمتباينة، والذي يجمع الأولين والآخرين."},
    {"name": "الغني", "transliteration": "Al-Ghaniyy", "meaning": "هو الذي لا يحتاج إلى شيء، وهو المستغني عن كل ما سواه، المفتقر إليه كل من عاداه."},
    {"name": "المغني", "transliteration": "Al-Mughni", "meaning": "هو معطي الغنى لعباده، يغني من يشاء غناه، وهو الكافي لمن شاء من عباده."},
    {"name": "المانع", "transliteration": "Al-Mani‘", "meaning": "هو الذي أعطى كل شيء، ويمنع العطاء عن من يشاء ابتلاء أو حماية."},
    {"name": "الضار", "transliteration": "Ad-Darr", "meaning": "هو المقدر للضر على من أراد كيف أراد، والمقدر النفع والخير لمن أراد كيف أراد كل ذلك على مقتضى حكمته سبحانه."},
    {"name": "النافع", "transliteration": "An-Nafi‘", "meaning": "هو المقدر للضر على من أراد كيف أراد، والمقدر النفع والخير لمن أراد كيف أراد كل ذلك على مقتضى حكمته سبحانه."},
    {"name": "النور", "transliteration": "An-Nur", "meaning": "هو الهادي الرشيد الذي يرشد بهدايته من يشاء فيبين له الحق، ويلهمه اتباعه، الظاهر في ذاته، المظهر لغيره."},
    {"name": "الهادي", "transliteration": "Al-Hadi", "meaning": "هو المبين للخلق طريق الحق بكلامه يهدي القلوب إلى معرفته، والنفوس إلى طاعته."},
    {"name": "البديع", "transliteration": "Al-Badi‘", "meaning": "هو الذي لا يماثله أحد في صفاته ولا في حكم من أحكامه، أو أمر من أموره، فهو المحدث الموجد على غير مثال."},
    {"name": "الباقي", "transliteration": "Al-Baqi", "meaning": "هو وحده له البقاء، الدائم الوجود الموصوف بالبقاء الأزلي، غير قابل للفناء فهو الباقي بلا انتهاء."},
    {"name": "الوارث", "transliteration": "Al-Warith", "meaning": "هو الأبقى الدائم الذي يرث الخلائق بعد فناء الخلق، وهو يرث الأرض ومن عليها."},
    {"name": "الرشيد", "transliteration": "Ar-Rasheed", "meaning": "هو الذي أسعد من شاء بإرشاده، وأشقى من شاء بإبعاده، عظيم الحكمة بالغ الرشاد."},
    {"name": "الصبور", "transliteration": "As-Saboor", "meaning": "هو الحليم الذي لا يعاجل العصاة بالنقمة، بل يعفوا ويؤخر، ولا يسرع بالفعل قبل أوانه."}
  ];
